// src/components/Timeline.jsx
import './Timeline.css';

const events = [
  { date: 'May 01, 2025', label: 'Registration Opens', sub: 'Portal goes live' },
  { date: 'June 10, 2025', label: 'Registration Closes', sub: 'Limited seats only' },
  { date: 'June 20, 2025', label: 'Hackathon Begins', sub: '24hr build window' },
  { date: 'June 21, 2025', label: 'Submission Deadline', sub: '11:59 PM sharp' },
  { date: 'June 25, 2025', label: 'Final Presentations', sub: 'Winners announced' },
];

export default function Timeline() {
  return (
    <section id="timeline" className="timeline-section">
      <p className="section-tag">Schedule</p>
      <h2 className="section-title">
        Event <span className="gradient-text">Timeline</span>
      </h2>
      <p className="section-desc">
        Mark your calendar. Every date below is critical to your participation journey.
      </p>

      {/* Horizontal scrollable timeline */}
      <div className="timeline-track fade-in">
        <div className="timeline-line" />
        {events.map(({ date, label, sub }) => (
          <div className="tl-item" key={label}>
            <div className="tl-dot" />
            <div className="tl-date">{date}</div>
            <div className="tl-label">{label}</div>
            <div className="tl-sub">{sub}</div>
          </div>
        ))}
      </div>
    </section>
  );
}
